"use client";

import { useState, useRef, useEffect } from "react";

export default function InventoryExtractionTool() {
  const [businessId, setBusinessId] = useState("demo-business");
  const [templateFile, setTemplateFile] = useState(null);
  const [templateStatus, setTemplateStatus] = useState(null); // null | 'uploaded' | 'error'
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [extracting, setExtracting] = useState(false);
  const [results, setResults] = useState(null);
  const [statusMessage, setStatusMessage] = useState({ type: "ready", text: "Ready (No Template)" });
  const [exportData, setExportData] = useState(null);

  const imageInputRef = useRef(null);
  const cameraInputRef = useRef(null);
  const templateInputRef = useRef(null);

  // Handle image file selection (from gallery or camera)
  const handleImageSelect = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImageFile(file);
    const reader = new FileReader();
    reader.onload = (ev) => setImagePreview(ev.target.result);
    reader.readAsDataURL(file);
    setResults(null);
    setExportData(null);
  };

  // Handle template upload
  const handleTemplateUpload = async () => {
    if (!templateFile) return;
    setUploading(true);
    setStatusMessage({ type: "info", text: "Uploading template..." });
    try {
      const formData = new FormData();
      formData.append("file", templateFile);
      formData.append("businessId", businessId);
      const res = await fetch("/api/upload-template", { method: "POST", body: formData });
      if (!res.ok) throw new Error("Upload failed");
      setTemplateStatus("uploaded");
      setStatusMessage({ type: "success", text: "Template uploaded! Ready to extract." });
    } catch (err) {
      setTemplateStatus("error");
      setStatusMessage({ type: "error", text: "Template upload failed. Try again." });
    } finally {
      setUploading(false);
    }
  };

  // Handle image extraction
  const handleExtract = async () => {
    if (!imageFile) {
      setStatusMessage({ type: "error", text: "Please select an image first." });
      return;
    }
    setExtracting(true);
    setStatusMessage({ type: "info", text: "Extracting inventory data..." });
    try {
      const formData = new FormData();
      formData.append("image", imageFile);
      formData.append("businessId", businessId);
      const res = await fetch("/api/extract-inventory", { method: "POST", body: formData });
      if (!res.ok) throw new Error("Extraction failed");
      const data = await res.json();
      setResults(data.items || []);
      setExportData(data);
      setStatusMessage({ type: "success", text: `Extracted ${data.items?.length ?? 0} items successfully!` });
    } catch (err) {
      setStatusMessage({ type: "error", text: "Extraction failed. Please try again." });
    } finally {
      setExtracting(false);
    }
  };

  // Export as CSV
  const handleExportCSV = () => {
    if (!results?.length) return;
    const headers = Object.keys(results[0]).join(",");
    const rows = results.map((row) => Object.values(row).map((v) => `"${v}"`).join(","));
    const csv = [headers, ...rows].join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `inventory-${Date.now()}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  // Export as JSON
  const handleExportJSON = () => {
    if (!results?.length) return;
    const blob = new Blob([JSON.stringify(results, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `inventory-${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const statusColors = {
    ready: "bg-green-50 border-green-400 text-green-700",
    success: "bg-green-50 border-green-400 text-green-700",
    info: "bg-blue-50 border-blue-400 text-blue-700",
    error: "bg-red-50 border-red-400 text-red-700",
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-28">
      {/* Header */}
      <div className="bg-white shadow-sm px-4 pt-6 pb-4 text-center">
        <h1 className="text-3xl font-extrabold text-gray-900 leading-tight">
          Inventory<br />Extraction Tool
        </h1>
      </div>

      <div className="max-w-lg mx-auto px-4 mt-4 space-y-5">

        {/* ── HERO: Camera / Upload Button ── */}
        <div className="bg-white rounded-2xl shadow-md p-5">
          <h2 className="text-xl font-bold text-gray-800 mb-3 flex items-center gap-2">
            📸 Capture or Upload Image
          </h2>

          {/* Image preview */}
          {imagePreview && (
            <div className="mb-4 rounded-xl overflow-hidden border border-gray-200">
              <img src={imagePreview} alt="Selected inventory" className="w-full object-cover max-h-52" />
              <p className="text-xs text-gray-500 text-center py-1 bg-gray-50">{imageFile?.name}</p>
            </div>
          )}

          {/* Two big action buttons */}
          <div className="grid grid-cols-2 gap-3">
            {/* Camera button */}
            <button
              onClick={() => cameraInputRef.current?.click()}
              className="flex flex-col items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 active:bg-indigo-800 text-white font-semibold rounded-xl py-5 transition-colors shadow"
            >
              <span className="text-3xl">📷</span>
              <span className="text-sm">Take Photo</span>
            </button>
            <input
              ref={cameraInputRef}
              type="file"
              accept="image/*"
              capture="environment"
              className="hidden"
              onChange={handleImageSelect}
            />

            {/* Upload from gallery */}
            <button
              onClick={() => imageInputRef.current?.click()}
              className="flex flex-col items-center justify-center gap-2 bg-indigo-100 hover:bg-indigo-200 active:bg-indigo-300 text-indigo-800 font-semibold rounded-xl py-5 transition-colors shadow"
            >
              <span className="text-3xl">🖼️</span>
              <span className="text-sm">Choose Photo</span>
            </button>
            <input
              ref={imageInputRef}
              type="file"
              accept="image/*"
              className="hidden"
              onChange={handleImageSelect}
            />
          </div>

          {/* Extract button */}
          {imageFile && (
            <button
              onClick={handleExtract}
              disabled={extracting}
              className="mt-4 w-full bg-emerald-600 hover:bg-emerald-700 active:bg-emerald-800 disabled:opacity-60 text-white font-bold rounded-xl py-4 text-lg transition-colors shadow-md"
            >
              {extracting ? "⏳ Extracting..." : "🔍 Extract Inventory"}
            </button>
          )}
        </div>

        {/* ── Status Banner ── */}
        <div className={`rounded-xl border-l-4 px-4 py-3 font-semibold text-center ${statusColors[statusMessage.type]}`}>
          Status: {statusMessage.text}
        </div>

        {/* ── Results Table ── */}
        {results && results.length > 0 && (
          <div className="bg-white rounded-2xl shadow-md p-4">
            <h2 className="text-xl font-bold text-gray-800 mb-3">📋 Extracted Items ({results.length})</h2>
            <div className="overflow-x-auto">
              <table className="w-full text-sm border-collapse">
                <thead>
                  <tr className="bg-gray-100">
                    {Object.keys(results[0]).map((key) => (
                      <th key={key} className="text-left px-3 py-2 font-semibold text-gray-600 border-b border-gray-200 whitespace-nowrap">
                        {key}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {results.map((row, i) => (
                    <tr key={i} className={i % 2 === 0 ? "bg-white" : "bg-gray-50"}>
                      {Object.values(row).map((val, j) => (
                        <td key={j} className="px-3 py-2 border-b border-gray-100 text-gray-700 whitespace-nowrap">
                          {String(val)}
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {results && results.length === 0 && (
          <div className="bg-yellow-50 border border-yellow-300 rounded-xl px-4 py-3 text-yellow-700 text-center font-medium">
            No items were extracted. Try a clearer image.
          </div>
        )}

        {/* ── Template Management (collapsed below main action) ── */}
        <details className="bg-white rounded-2xl shadow-md">
          <summary className="px-5 py-4 cursor-pointer font-bold text-gray-800 text-lg flex items-center gap-2 select-none">
            📋 Template Management
          </summary>
          <div className="px-5 pb-5 space-y-3 border-t border-gray-100 pt-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Business ID</label>
              <input
                type="text"
                value={businessId}
                onChange={(e) => setBusinessId(e.target.value)}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-400"
              />
            </div>

            <div>
              <p className="text-sm text-gray-500 mb-2">
                {templateStatus === "uploaded"
                  ? "✅ Template uploaded. Extraction accuracy improved."
                  : "No template uploaded yet. Upload one to improve extraction accuracy!"}
              </p>
              <button
                onClick={() => templateInputRef.current?.click()}
                className="w-full border-2 border-dashed border-gray-300 hover:border-indigo-400 rounded-xl py-4 text-gray-500 hover:text-indigo-600 text-sm font-medium transition-colors"
              >
                {templateFile ? `📄 ${templateFile.name}` : "Choose template file (.xlsx or .csv)"}
              </button>
              <input
                ref={templateInputRef}
                type="file"
                accept=".xlsx,.csv"
                className="hidden"
                onChange={(e) => setTemplateFile(e.target.files?.[0] || null)}
              />
            </div>

            {templateFile && (
              <button
                onClick={handleTemplateUpload}
                disabled={uploading}
                className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:opacity-60 text-white font-semibold rounded-xl py-3 transition-colors"
              >
                {uploading ? "Uploading..." : "Upload Template"}
              </button>
            )}
          </div>
        </details>

      </div>

      {/* ── STICKY EXPORT BAR ── */}
      <div className="fixed bottom-0 left-0 right-0 z-50 bg-white border-t border-gray-200 shadow-2xl px-4 py-3">
        <div className="max-w-lg mx-auto">
          {results && results.length > 0 ? (
            <div className="grid grid-cols-2 gap-3">
              <button
                onClick={handleExportCSV}
                className="flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-700 active:bg-emerald-800 text-white font-bold rounded-xl py-3 text-base transition-colors shadow"
              >
                <span>📊</span> Export CSV
              </button>
              <button
                onClick={handleExportJSON}
                className="flex items-center justify-center gap-2 bg-gray-800 hover:bg-gray-900 active:bg-black text-white font-bold rounded-xl py-3 text-base transition-colors shadow"
              >
                <span>📁</span> Export JSON
              </button>
            </div>
          ) : (
            <div className="flex items-center justify-center gap-2 text-gray-400 py-2 text-sm font-medium">
              <span>📤</span> Export will appear here after extraction
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

